CREATE TABLE videos (id SERIAL PRIMARY KEY, title VARCHAR(255) NOT NULL, description TEXT, url TEXT NOT NULL, thumbnail_url TEXT, uploaded_by INTEGER REFERENCES users(id), views INTEGER DEFAULT 0, created_at TIMESTAMP DEFAULT NOW()); CREATE TABLE grades (id SERIAL PRIMARY KEY, from_user_id INTEGER REFERENCES users(id), to_user_id INTEGER REFERENCES users(id), score INTEGER NOT NULL, comment TEXT, created_at TIMESTAMP DEFAULT NOW()); CREATE TABLE tasks (id SERIAL PRIMARY KEY, title VARCHAR(255) NOT NULL, description TEXT, assigned_to INTEGER REFERENCES users(id), created_by INTEGER REFERENCES users(id), status VARCHAR(20) DEFAULT 'pending', priority VARCHAR(10) DEFAULT 'medium', due_date TIMESTAMP, created_at TIMESTAMP DEFAULT NOW(), updated_at TIMESTAMP DEFAULT NOW()); CREATE TABLE donations (id SERIAL PRIMARY KEY, user_id INTEGER REFERENCES users(id), amount INTEGER NOT NULL, level INTEGER NOT NULL DEFAULT 1, granted_by INTEGER REFERENCES users(id), expires_at TIMESTAMP, note TEXT, created_at TIMESTAMP DEFAULT NOW()); CREATE TABLE news (id SERIAL PRIMARY KEY, title VARCHAR(255) NOT NULL, content TEXT NOT NULL, author_id INTEGER REFERENCES users(id), pinned BOOLEAN DEFAULT FALSE, created_at TIMESTAMP DEFAULT NOW());